import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import { NotificationService, resetNotificationIdCounter } from '../../src/services/notification.service.js';
import { PreferencesService, resetPreferencesIdCounter } from '../../src/services/preferences.service.js';
import { NotificationHistoryService, resetLogIdCounter } from '../../src/services/notification-history.service.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import { EmailAdapter, InMemoryTransport } from '../../src/adapters/email.adapter.js';
import { SmsAdapter, InMemorySmsTransport } from '../../src/adapters/sms.adapter.js';
import { WebhookAdapter, InMemoryWebhookTransport } from '../../src/adapters/webhook.adapter.js';
import { Database } from '../../src/utils/database.js';
import type { NotificationPayload } from '../../src/models/notification.js';

describe('Notification Pipeline Integration', () => {
  let db: Database;
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let preferencesService: PreferencesService;
  let historyService: NotificationHistoryService;
  let preferencesRepo: PreferencesRepository;
  let logRepo: NotificationLogRepository;
  let emailTransport: InMemoryTransport;
  let smsTransport: InMemorySmsTransport;
  let webhookTransport: InMemoryWebhookTransport;

  beforeEach(() => {
    // Reset ID counters
    resetNotificationIdCounter();
    resetPreferencesIdCounter();
    resetLogIdCounter();

    // Fresh database and event bus
    db = new Database();
    eventBus = new EventBus();

    // Repositories
    preferencesRepo = new PreferencesRepository(db);
    logRepo = new NotificationLogRepository(db);

    // Services
    preferencesService = new PreferencesService(preferencesRepo);
    historyService = new NotificationHistoryService(logRepo);
    notificationService = new NotificationService(eventBus);
    notificationService.setPreferencesService(preferencesService);
    notificationService.setHistoryService(historyService);

    // Adapters with in-memory transports
    emailTransport = new InMemoryTransport();
    smsTransport = new InMemorySmsTransport();
    webhookTransport = new InMemoryWebhookTransport();

    notificationService.registerAdapter(
      new EmailAdapter({ fromAddress: 'noreply@taskflow.com', transport: emailTransport }),
    );
    notificationService.registerAdapter(
      new SmsAdapter({ fromNumber: '+15551234567', transport: smsTransport }),
    );
    notificationService.registerAdapter(
      new WebhookAdapter({ url: 'https://hooks.example.com/notify', transport: webhookTransport }),
    );
  });

  // ── Email channel ──────────────────────────────────────────────────

  describe('email channel end-to-end', () => {
    it('should deliver an email notification and log it in history', async () => {
      const payload: NotificationPayload = {
        type: 'order:confirmation',
        recipient: 'alice@example.com',
        subject: 'Order Confirmation: ORD-1',
        body: 'Your order has been placed.',
        channel: 'email',
        priority: 'normal',
        metadata: { orderId: 'ORD-1' },
      };

      const result = await notificationService.send(payload);

      expect(result.success).toBe(true);
      expect(result.channel).toBe('email');

      // Email actually sent via transport
      expect(emailTransport.sent).toHaveLength(1);
      expect(emailTransport.sent[0]!.to).toBe('alice@example.com');
      expect(emailTransport.sent[0]!.subject).toBe('Order Confirmation: ORD-1');
      expect(emailTransport.sent[0]!.html).toContain('Order Confirmed');

      // History recorded
      const history = historyService.getByRecipient('alice@example.com');
      expect(history).toHaveLength(1);
      expect(history[0]!.status).toBe('sent');
      expect(history[0]!.channel).toBe('email');
    });

    it('should respect email preferences — enabled user receives email', async () => {
      // Explicitly enable email for user
      preferencesService.updateEmailPreferences('alice@example.com', { enabled: true });

      const result = await notificationService.send({
        type: 'user:welcome',
        recipient: 'alice@example.com',
        subject: 'Welcome!',
        body: 'Welcome to TaskFlow Pro.',
        channel: 'email',
        priority: 'normal',
      });

      expect(result.success).toBe(true);
      expect(emailTransport.sent).toHaveLength(1);
    });
  });

  // ── SMS channel ────────────────────────────────────────────────────

  describe('SMS channel end-to-end', () => {
    it('should deliver an SMS notification and log it in history', async () => {
      const payload: NotificationPayload = {
        type: 'order:status-update',
        recipient: '+15559876543',
        subject: 'Order Update',
        body: 'Your order has shipped.',
        channel: 'sms',
        priority: 'high',
      };

      const result = await notificationService.send(payload);

      expect(result.success).toBe(true);
      expect(result.channel).toBe('sms');

      // SMS actually sent via transport
      expect(smsTransport.sent).toHaveLength(1);
      expect(smsTransport.sent[0]!.to).toBe('+15559876543');
      expect(smsTransport.sent[0]!.body).toContain('Order Update');
      expect(smsTransport.sent[0]!.body).toContain('Your order has shipped.');

      // History recorded
      const history = historyService.getByRecipient('+15559876543');
      expect(history).toHaveLength(1);
      expect(history[0]!.status).toBe('sent');
      expect(history[0]!.channel).toBe('sms');
    });

    it('should respect SMS preferences — enabled user receives SMS', async () => {
      preferencesService.updateSmsPreferences('+15559876543', { enabled: true });

      const result = await notificationService.send({
        type: 'order:confirmation',
        recipient: '+15559876543',
        subject: 'Order Placed',
        body: 'Your order was placed.',
        channel: 'sms',
        priority: 'normal',
      });

      expect(result.success).toBe(true);
      expect(smsTransport.sent).toHaveLength(1);
    });
  });

  // ── Webhook channel ────────────────────────────────────────────────

  describe('webhook channel end-to-end', () => {
    it('should deliver a webhook notification and log it in history', async () => {
      const payload: NotificationPayload = {
        type: 'order:confirmation',
        recipient: 'tenant-42',
        subject: 'New Order',
        body: 'A new order was created.',
        channel: 'webhook',
        priority: 'normal',
        metadata: { orderId: 'ORD-5' },
      };

      const result = await notificationService.send(payload);

      expect(result.success).toBe(true);
      expect(result.channel).toBe('webhook');

      // Webhook actually sent via transport
      expect(webhookTransport.sent).toHaveLength(1);
      const request = webhookTransport.sent[0]!;
      expect(request.url).toBe('https://hooks.example.com/notify');
      const body = JSON.parse(request.body);
      expect(body.event).toBe('order:confirmation');
      expect(body.recipient).toBe('tenant-42');

      // History recorded
      const history = historyService.getByRecipient('tenant-42');
      expect(history).toHaveLength(1);
      expect(history[0]!.status).toBe('sent');
      expect(history[0]!.channel).toBe('webhook');
    });
  });

  // ── Preferences suppression ────────────────────────────────────────

  describe('preferences suppression', () => {
    it('should suppress email when email channel is disabled', async () => {
      preferencesService.updateEmailPreferences('alice@example.com', { enabled: false });

      const result = await notificationService.send({
        type: 'order:confirmation',
        recipient: 'alice@example.com',
        subject: 'Order Placed',
        body: 'Details here.',
        channel: 'email',
        priority: 'normal',
      });

      expect(result.success).toBe(false);
      expect(result.error).toBe('Suppressed by user preferences');
      expect(emailTransport.sent).toHaveLength(0);

      // Suppressed notification still logged in history
      const history = historyService.getByRecipient('alice@example.com');
      expect(history).toHaveLength(1);
      expect(history[0]!.status).toBe('suppressed');
    });

    it('should suppress SMS when SMS channel is disabled', async () => {
      preferencesService.updateSmsPreferences('+15559876543', { enabled: false });

      const result = await notificationService.send({
        type: 'order:status-update',
        recipient: '+15559876543',
        subject: 'Update',
        body: 'Status changed.',
        channel: 'sms',
        priority: 'normal',
      });

      expect(result.success).toBe(false);
      expect(result.error).toBe('Suppressed by user preferences');
      expect(smsTransport.sent).toHaveLength(0);

      const history = historyService.getByRecipient('+15559876543');
      expect(history).toHaveLength(1);
      expect(history[0]!.status).toBe('suppressed');
    });

    it('should suppress webhook when webhook channel is disabled', async () => {
      preferencesService.updateWebhookPreferences('tenant-42', { enabled: false });

      const result = await notificationService.send({
        type: 'order:confirmation',
        recipient: 'tenant-42',
        subject: 'New Order',
        body: 'Details.',
        channel: 'webhook',
        priority: 'normal',
      });

      expect(result.success).toBe(false);
      expect(result.error).toBe('Suppressed by user preferences');
      expect(webhookTransport.sent).toHaveLength(0);

      const history = historyService.getByRecipient('tenant-42');
      expect(history).toHaveLength(1);
      expect(history[0]!.status).toBe('suppressed');
    });

    it('should suppress email for a specific category even when email is globally enabled', async () => {
      preferencesService.updateEmailPreferences('alice@example.com', {
        enabled: true,
        categorySubscriptions: { 'order:status-update': false },
      });

      const result = await notificationService.send({
        type: 'order:status-update',
        recipient: 'alice@example.com',
        subject: 'Order Update',
        body: 'Status changed.',
        channel: 'email',
        priority: 'normal',
      });

      expect(result.success).toBe(false);
      expect(result.error).toBe('Suppressed by user preferences');
      expect(emailTransport.sent).toHaveLength(0);
    });

    it('should allow notification when no preferences exist (opt-out model)', async () => {
      // No preferences set for this user — default is to allow
      const result = await notificationService.send({
        type: 'user:welcome',
        recipient: 'newuser@example.com',
        subject: 'Welcome',
        body: 'Welcome!',
        channel: 'email',
        priority: 'normal',
      });

      expect(result.success).toBe(true);
      expect(emailTransport.sent).toHaveLength(1);
    });
  });

  // ── History logging ────────────────────────────────────────────────

  describe('history logging', () => {
    it('should log all notification outcomes across channels', async () => {
      // Successful email
      await notificationService.send({
        type: 'order:confirmation',
        recipient: 'alice@example.com',
        subject: 'Order Email',
        body: 'Email body.',
        channel: 'email',
        priority: 'normal',
      });

      // Successful SMS
      await notificationService.send({
        type: 'order:confirmation',
        recipient: '+15559876543',
        subject: 'Order SMS',
        body: 'SMS body.',
        channel: 'sms',
        priority: 'normal',
      });

      // Successful webhook
      await notificationService.send({
        type: 'order:confirmation',
        recipient: 'tenant-42',
        subject: 'Order Webhook',
        body: 'Webhook body.',
        channel: 'webhook',
        priority: 'normal',
      });

      expect(historyService.getCount()).toBe(3);

      const emailLogs = historyService.query({ channel: 'email' });
      expect(emailLogs).toHaveLength(1);
      expect(emailLogs[0]!.status).toBe('sent');

      const smsLogs = historyService.query({ channel: 'sms' });
      expect(smsLogs).toHaveLength(1);
      expect(smsLogs[0]!.status).toBe('sent');

      const webhookLogs = historyService.query({ channel: 'webhook' });
      expect(webhookLogs).toHaveLength(1);
      expect(webhookLogs[0]!.status).toBe('sent');
    });

    it('should record failed delivery in history', async () => {
      // Send to an invalid email — EmailAdapter will catch it and return failure
      const result = await notificationService.send({
        type: 'user:welcome',
        recipient: 'not-an-email',
        subject: 'Welcome',
        body: 'Welcome!',
        channel: 'email',
        priority: 'normal',
      });

      expect(result.success).toBe(false);

      const history = historyService.getByRecipient('not-an-email');
      expect(history).toHaveLength(1);
      expect(history[0]!.status).toBe('failed');
      expect(history[0]!.error).toBeDefined();
    });

    it('should log suppressed and sent notifications separately', async () => {
      // Disable email for alice
      preferencesService.updateEmailPreferences('alice@example.com', { enabled: false });

      // Suppressed
      await notificationService.send({
        type: 'order:confirmation',
        recipient: 'alice@example.com',
        subject: 'Order 1',
        body: 'body',
        channel: 'email',
        priority: 'normal',
      });

      // Sent (bob has no prefs — default allow)
      await notificationService.send({
        type: 'order:confirmation',
        recipient: 'bob@example.com',
        subject: 'Order 2',
        body: 'body',
        channel: 'email',
        priority: 'normal',
      });

      const suppressedLogs = historyService.query({ status: 'suppressed' });
      expect(suppressedLogs).toHaveLength(1);
      expect(suppressedLogs[0]!.recipient).toBe('alice@example.com');

      const sentLogs = historyService.query({ status: 'sent' });
      expect(sentLogs).toHaveLength(1);
      expect(sentLogs[0]!.recipient).toBe('bob@example.com');
    });

    it('should preserve notification metadata in history entries', async () => {
      await notificationService.send({
        type: 'order:confirmation',
        recipient: 'alice@example.com',
        subject: 'Order Placed',
        body: 'Your order was placed.',
        channel: 'email',
        priority: 'high',
        metadata: { orderId: 'ORD-99' },
      });

      const history = historyService.getByRecipient('alice@example.com');
      expect(history).toHaveLength(1);
      expect(history[0]!.priority).toBe('high');
      expect(history[0]!.type).toBe('order:confirmation');
      expect(history[0]!.subject).toBe('Order Placed');
      // metadata gets enriched with notificationId by NotificationService
      expect(history[0]!.metadata).toMatchObject({ orderId: 'ORD-99' });
    });
  });

  // ── Event-driven integration ───────────────────────────────────────

  describe('event-driven notification flow', () => {
    it('should send email when order:created event fires', async () => {
      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'ORD-10',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 3, unitPrice: 15 }],
          total: 45,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      });

      // Email sent through the full pipeline
      expect(emailTransport.sent).toHaveLength(1);
      expect(emailTransport.sent[0]!.to).toBe('alice@example.com');
      expect(emailTransport.sent[0]!.subject).toContain('Order Confirmation');

      // History recorded
      expect(historyService.getCount()).toBe(1);
      const history = historyService.getByRecipient('alice@example.com');
      expect(history[0]!.status).toBe('sent');
    });

    it('should suppress event-driven email when preferences disallow it', async () => {
      preferencesService.updateEmailPreferences('alice@example.com', { enabled: false });

      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'ORD-11',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      });

      expect(emailTransport.sent).toHaveLength(0);
      const history = historyService.getByRecipient('alice@example.com');
      expect(history).toHaveLength(1);
      expect(history[0]!.status).toBe('suppressed');
    });
  });

  // ── Notification ordering ──────────────────────────────────────────

  describe('notification ordering', () => {
    it('should preserve send order for same recipient across multiple notifications', async () => {
      const subjects = ['First', 'Second', 'Third', 'Fourth'];
      const sendPromises = subjects.map((subject) =>
        notificationService.send({
          type: 'order:confirmation',
          recipient: 'alice@example.com',
          subject,
          body: `Body for ${subject}`,
          channel: 'email',
          priority: 'normal',
        }),
      );

      await Promise.all(sendPromises);

      // Emails should arrive in the order they were sent
      const sentSubjects = emailTransport.sent.map((e) => e.subject);
      expect(sentSubjects).toEqual([
        'Order Confirmation: ORD-1',  // template overrides subject for order:confirmation
        'Order Confirmation: ORD-1',
        'Order Confirmation: ORD-1',
        'Order Confirmation: ORD-1',
      ]);

      // More importantly: internal notifications are in order
      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(4);
      expect(notifications[0]!.id).toBe('notif-0001');
      expect(notifications[1]!.id).toBe('notif-0002');
      expect(notifications[2]!.id).toBe('notif-0003');
      expect(notifications[3]!.id).toBe('notif-0004');
    });

    it('should maintain per-recipient ordering while allowing cross-recipient concurrency', async () => {
      const deliveryLog: string[] = [];
      const originalSend = emailTransport.sendMail.bind(emailTransport);

      // Track delivery order
      emailTransport.sendMail = async (email) => {
        deliveryLog.push(email.to);
        return originalSend(email);
      };

      // Send two to alice, one to bob
      const p1 = notificationService.send({
        type: 'order:confirmation',
        recipient: 'alice@example.com',
        subject: 'Alice Order 1',
        body: 'body',
        channel: 'email',
        priority: 'normal',
      });
      const p2 = notificationService.send({
        type: 'order:status-update',
        recipient: 'alice@example.com',
        subject: 'Alice Order 2',
        body: 'body',
        channel: 'email',
        priority: 'normal',
      });
      const p3 = notificationService.send({
        type: 'order:confirmation',
        recipient: 'bob@example.com',
        subject: 'Bob Order 1',
        body: 'body',
        channel: 'email',
        priority: 'normal',
      });

      await Promise.all([p1, p2, p3]);

      // Alice's notifications should be in order relative to each other
      const aliceDeliveries = deliveryLog
        .map((to, i) => ({ to, i }))
        .filter((d) => d.to === 'alice@example.com');
      expect(aliceDeliveries).toHaveLength(2);
      expect(aliceDeliveries[0]!.i).toBeLessThan(aliceDeliveries[1]!.i);
    });
  });

  // ── Multi-channel for same user ────────────────────────────────────

  describe('multi-channel notification', () => {
    it('should deliver same notification type across different channels independently', async () => {
      // Send an order confirmation via email and webhook
      const emailResult = await notificationService.send({
        type: 'order:confirmation',
        recipient: 'alice@example.com',
        subject: 'Order Placed',
        body: 'Your order was placed.',
        channel: 'email',
        priority: 'normal',
      });
      const webhookResult = await notificationService.send({
        type: 'order:confirmation',
        recipient: 'alice@example.com',
        subject: 'Order Placed',
        body: 'Your order was placed.',
        channel: 'webhook',
        priority: 'normal',
      });

      expect(emailResult.success).toBe(true);
      expect(webhookResult.success).toBe(true);
      expect(emailTransport.sent).toHaveLength(1);
      expect(webhookTransport.sent).toHaveLength(1);

      // Both logged in history
      const history = historyService.getByRecipient('alice@example.com');
      expect(history).toHaveLength(2);
      expect(history.map((h) => h.channel).sort()).toEqual(['email', 'webhook']);
    });

    it('should suppress one channel while allowing another for the same user', async () => {
      // Disable email, keep webhook enabled
      preferencesService.updateEmailPreferences('alice@example.com', { enabled: false });
      preferencesService.updateWebhookPreferences('alice@example.com', { enabled: true });

      const emailResult = await notificationService.send({
        type: 'order:confirmation',
        recipient: 'alice@example.com',
        subject: 'Order',
        body: 'body',
        channel: 'email',
        priority: 'normal',
      });
      const webhookResult = await notificationService.send({
        type: 'order:confirmation',
        recipient: 'alice@example.com',
        subject: 'Order',
        body: 'body',
        channel: 'webhook',
        priority: 'normal',
      });

      expect(emailResult.success).toBe(false);
      expect(webhookResult.success).toBe(true);
      expect(emailTransport.sent).toHaveLength(0);
      expect(webhookTransport.sent).toHaveLength(1);

      const history = historyService.getByRecipient('alice@example.com');
      expect(history).toHaveLength(2);
      const statuses = history.map((h) => `${h.channel}:${h.status}`).sort();
      expect(statuses).toEqual(['email:suppressed', 'webhook:sent']);
    });
  });

  // ── notification:sent event ────────────────────────────────────────

  describe('notification:sent event emission', () => {
    it('should emit notification:sent event on successful delivery', async () => {
      const events = eventBus.getEventLog();

      await notificationService.send({
        type: 'user:welcome',
        recipient: 'alice@example.com',
        subject: 'Welcome',
        body: 'Welcome!',
        channel: 'email',
        priority: 'normal',
      });

      const sentEvents = events.filter((e) => e.type === 'notification:sent');
      expect(sentEvents).toHaveLength(1);
    });

    it('should NOT emit notification:sent event when notification is suppressed', async () => {
      preferencesService.updateEmailPreferences('alice@example.com', { enabled: false });

      await notificationService.send({
        type: 'user:welcome',
        recipient: 'alice@example.com',
        subject: 'Welcome',
        body: 'Welcome!',
        channel: 'email',
        priority: 'normal',
      });

      const events = eventBus.getEventLog();
      const sentEvents = events.filter((e) => e.type === 'notification:sent');
      expect(sentEvents).toHaveLength(0);
    });
  });
});

